var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배, 이것 좀 보세요. 인터넷에서 어딜 가나 펠리세트 이야기뿐이에요.","JPN":"ミナ先輩、これ見てください。ネットのどこを見てもフェリセットの話ばかりです。","ENG":"Look, Mina. Félicette is all over the internet!","TWN":"米娜前輩，你看這個。現在網路上到處都是費莉塞特的發言。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇겠지. 생방송에서 그런 식으로 저질렀으니까.","JPN":"当然だよ。生放送であんな風にやらかしたんだから。","ENG":"Of course she is. She said those words on live TV.","TWN":"想也知道，誰叫她在直播中大放厥詞。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그걸 무마하는 사장님 인맥도 신기하긴 하지만….","JPN":"それを収める社長の人脈も不思議だけど……","ENG":"It's amazing how Boss uses his connections to cover it up, though...","TWN":"不過老闆竟然能把這件事壓下來，看來老闆的人脈也是很驚人……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"운이 좋았지. 알파트릭스가 협찬사였으니.","JPN":"運がよかったのさ。アルファトリックスがスポンサーだったからな。","ENG":"We were lucky that Alphatrix was the sponsor.","TWN":"只能說是運氣好，剛好阿爾法崔克斯是贊助方。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하긴…. 거기 그룹 회장님이랑 알고 지내는 사이였지?","JPN":"まあ、確かに……そのグループの会長と知り合いだったよね？","ENG":"Oh, right... He knows the President.","TWN":"也是……你和那個集團的會長是認識的吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"분해요! 분해서 참을 수가 없어요, 선배!","JPN":"悔しいです！　悔しくてたまりません、先輩！","ENG":"I can't take it anymore! It's so unfair!","TWN":"很生氣欸！我太生氣啦！前輩！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트 때문에 제가 부른 펜릴 소대 테마송은 완전 묻혀 버렸다구요!","JPN":"フェリセットのせいで、私が歌ったフェンリル小隊のテーマソングは完全に無視されちゃったんですよ！","ENG":"Because of Félicette, my Fenrir Squad theme song was completely forgotten!","TWN":"費莉塞特害我唱的芬里爾小隊主題曲都被剪掉咧！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……묻혀서 다행이야. 정말로.","JPN":"……無視されてよかった。本当に。","ENG":"...I am so glad that it did.","TWN":"……真是萬幸。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미안하게 됐어. 당분간은 다들 밤길 조심해.","JPN":"悪いな。しばらくはみんな、夜道は気をつけてくれよ。","ENG":"I'm sorry about this. In the meantime, keep an eye out when you're outdoors.","TWN":"對不起，這段時間大家夜裡出門都小心點。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그릴 파티도 언더그라운드 출신이라 뒤에서 하는 짓이 좀 지저분하거든.","JPN":"グリルパーティーもアンダーグラウンド出身だから、裏でちょっと汚いことしてるんだよ。","ENG":"Grill Party also started from the Underground. They do some sketchy things behind the curtains.","TWN":"格里爾派提也是出身於地下世界，做事的手段有點骯髒。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그건 걱정하지 않아도 돼요.","JPN":"それは心配しなくて大丈夫よ。","ENG":"Don't worry about it.","TWN":"不用擔心。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 잘난 1, 2 소대로 예선에서 탈락하면 회사부터 간수해야 할 테니까요.","JPN":"その自慢の第1、第2小隊が予選落ちしたら、まず会社から守らないといけなくなるだろうから。","ENG":"They'll be busy trying to save their company when their stuck-up squads fail to make it past qualifiers.","TWN":"如果那個囂張的第1和第2小隊在預賽中被淘汰，他們就得先給公司一個交代。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트는 참 생각이 독하네요. 피도 눈물도 없어요.","JPN":"フェリセットって怖いこと考えるんですね。血も涙もありません。","ENG":"You can be really heartless at times, Félicette. So cold-blooded.","TWN":"費莉塞特的想法好狠毒，真是冷血無情。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 다들 주목.","JPN":"はい、みんな注目。","ENG":"All right. Attention, everyone.","TWN":"來，全員注意！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이제 예선전 강행군도 막바지야.","JPN":"予選の強行軍も大詰めよ。","ENG":"Qualifiers are coming to an end.","TWN":"現在預賽的賽程也已經接近尾聲。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이번 상대만 이기면 본선 진출 여부는 그릴 파티와의 경기에 달려 있어.","JPN":"次の相手にさえ勝てれば、本選進出の可否はグリルパーティーとの試合にかかってる。","ENG":"If we beat our next opponent, our match against Grill Party will determine whether we make it to the elimination rounds or not.","TWN":"這場打贏後，能否進入決賽的關鍵，就取決於我們和格里爾派提的比賽結果。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"우선 코치님 의견대로 노엘을 함께 움직이게 한 건 성과가 좋아.","JPN":"まずはコーチの意見どおり、ノエルを一緒に動かしたのはいい成果をあげたわ。","ENG":"First things first, it was a good idea to move with Noelle, just as Coach said.","TWN":"首先，我們聽從教練的意見，和洛艾兒一起行動的成績還是不錯的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"확실히…… 운용법만 바꿨을 뿐인데 무척 달라졌어요.","JPN":"確かに……運用方法を変えただけなのに、がらっと変わったわ。","ENG":"Yes... All we did was change our approach, and now it's way different.","TWN":"確實……只是單純改變行進方式，結果就發生巨大的變化。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"들었죠, 미나 선배? 저도 한 사람 몫을 하고 있어요!","JPN":"聞きましたよね？　ミナ先輩。私も一人前になってます！","ENG":"Did you hear that, Mina? I'm pulling my weight!","TWN":"聽到了吧，米娜前輩？我現在也能獨當一面囉！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"글쎄, 다른 사람들은 네가 요리만 해도 한 사람 몫은 한다고 생각할 것 같던데.","JPN":"さあ、他の人はあなたが料理をするだけでも一人前だと思いそうだけど。","ENG":"Well, I don't know. The others thought that your cooking for them was enough.","TWN":"這個嘛，我覺得大家的意思是指料理方面。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"가끔 이상한 재료 넣는 것만 빼면.","JPN":"たまに変な材料さえ入れなければ。","ENG":"Except for the times when you put weird ingredients in your dish.","TWN":"除了你偶爾會放一些奇怪的食材進去之外。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"히잉, 죄송해요. 크레페 속에 브로콜리를 넣으면 깜짝 선물 같을 줄 알았는데.","JPN":"ふえん、すみません。クレープの中にブロッコリーを入れると、サプライズになると思いました。","ENG":"Gah, I'm sorry. I thought it would be a pleasant surprise to put broccoli in crepes!","TWN":"呃呃，對不起。我以為在可麗餅裡放綠花椰會有驚喜的感覺。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니. 그건 깜짝 선물이 아니라 그냥 지뢰였어. 대전차 지뢰.","JPN":"いや。それはサプライズじゃなくてただの地雷だった。対戦車地雷。","ENG":"That wasn't a pleasant surprise, Noelle. It was like walking on a minefield of broccoli.","TWN":"不，那不是驚喜，是地雷！是戰車級地雷。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말하지 마세요. 또 나쁜 기억이 떠오르잖아요.","JPN":"言わないで。また悪い記憶が蘇るわ。","ENG":"Don't talk about it. You're making me remember terrible things.","TWN":"閉嘴萊卡，別再讓我想起不好的回憶。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"결과적으로 피격 횟수나 유효 공격 같은 주요 지표들도 호조야.","JPN":"結果的に、被撃回数や有効攻撃のような主要指標も好調よ。","ENG":"To summarize, our numbers for hits and effective shots have risen.","TWN":"整體來說，隊員的被擊中的次數，以及有效攻擊次數等主要指標表現得很好。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"따라서 현재로서는 팀원들의 컨디션을 유지하는 것이 최선이라고 판단됩니다, 코치님.","JPN":"よって、現時点としてはチームメンバーの体調を維持することがベストだと判断されます、コーチ。","ENG":"Which is why maintaining the players' conditions would be the best option for now, Coach.","TWN":"因此我認為，目前最好的辦法就是讓隊員保持這個狀態，教練。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 기분 전환 겸 외식도 괜찮겠군.","JPN":"それでは、気分転換に外食するのもいいな。","ENG":"Then I assume eating out would be a feasible option.","TWN":"那出去吃個飯也不錯，順便散散心。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"외식? 식당에서 돈을 내고 밥 먹는 사치를 누리자고?","JPN":"外食？　食堂でお金払ってご飯を食べる贅沢をするってこと？","ENG":"Eat out? You mean, we can enjoy the luxury of paying money at a restaurant to get a decent meal?","TWN":"出去吃飯？在餐廳花錢吃飯的奢侈享受嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"게다가 그걸 회사 돈으로? 그라운드 원은 다들 그렇게 인심이 후한 거야?","JPN":"しかも、それを会社のお金で？　グラウンド・ワンって、みんなそう太っ腹なのか？","ENG":"With company money, even? Man, is it you, or is everyone at Ground One so generous?","TWN":"而且花的還是公司的錢？G1的人都這麼厚道嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카는 여전히 거지 근성을 못 버렸네요.","JPN":"ライカは相変わらず乞食根性が抜けないのね。","ENG":"Laika still hasn't gotten over her poor man's habits.","TWN":"萊卡還是沒能丟掉乞丐的本性呢。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"전 찬성! 오면서 조사해 뒀던 맛집 중에 못 가 본 데가 많거든요.","JPN":"私は賛成！　ここに来る時に調べておいたグルメで、行けなかったところがたくさんありますから。","ENG":"I vote yes! There are a lot of places that I've been meaning to go to!","TWN":"我也贊成！還有好多我打聽到的美食店沒有去呢。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전 외식은 마지막 경기 뒤로 미루면 좋겠어요, 코치.","JPN":"私は外食は最後の試合の後にしてほしいです、コーチ。","ENG":"I think eating out should wait until after the final match, Coach.","TWN":"我希望把出去吃飯推遲到最後一場比賽之後，教練。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엣? 어째서요?","JPN":"えっ？　どうしてですか？","ENG":"Eh? Why?","TWN":"嗯？為什麼？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"해이해진 마음가짐이 경기 결과에 영향을 끼칠지도 모르니까요.","JPN":"気が緩むと、試合の結果に影響を及ぼすかもしれませんから。","ENG":"Because lowering our guard might lead to defeat.","TWN":"因為只要一放鬆就很可能會影響到比賽結果。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"지금은 외식 얘기보다 다음 상대가 중요해요.","JPN":"今は外食の話より、次の相手が重要です。","ENG":"Our next opponent is more important to us. Much more important than eating out.","TWN":"比起出去吃飯，現在分析下個對手比較重要。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"페넥폭스였지, 아마?","JPN":"フェネックフォックスだったよな？　たぶん。","ENG":"Fennec Fox, was it?","TWN":"沙狐小隊，對吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"맞아. 정식 명칭은 페넥폭스 협동조합. 로터스에선 꽤 규모 있는 태스크포스야.","JPN":"そう。正式名称はフェネックフォックス協同組合。ロータスではかなり大規模なタスクフォースだよ。","ENG":"Yes. Officially known as the Fennec Fox Association, they are an influential TASKFORCE in Lotus.","TWN":"沒錯。正式名稱是沙狐合作社，在洛德斯是頗具規模的一個特遣勢力。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"구식 장비를 사용하긴 하는데, 그걸 운용하는 실력이 상당하거든.","JPN":"旧式の装備を使ってるけど、それを運用する腕がすごいの。","ENG":"They use old equipment, but they are quite skilled in utilizing it.","TWN":"雖然使用的是老舊裝備，但技術與實力都相當出色。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이번 상대는 샤레이드에서 자발적으로 생겨난 지부지만.","JPN":"今度の相手はシャレードで自発的にできあがった支部だけどね。","ENG":"Our opponent is a new branch that started off in Charade, though.","TWN":"不過這次的對手是在查雷德自發性組成的分公司。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이른바 주니어라고나 할까?","JPN":"いわゆるジュニアってやつ？","ENG":"Juniors, I guess.","TWN":"該說是二代嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아쉽네요. 로터스 쪽 정예들에겐 배울 점이 많을 것 같았는데.","JPN":"残念ですね。ロータス側の精鋭には教わるところが多いと思ったのに。","ENG":"That's a shame. I thought we would be able to learn a lot from the elites at Lotus.","TWN":"真可惜。我還以為能從洛德斯的精英身上學些東西。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래도 몇십 년 전 장비를 쓰는 분들 아니었어요?","JPN":"でも、何十年も前の装備を使ってる方々じゃなかったんですか？","ENG":"Don't they still use ancient equipment, though?","TWN":"不過再怎麼說，他們使用的不也是幾十年前的裝備嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"차원 함선도 쓰고 광선도 쏘는 세상인데…. 그렇게나 위협적인 거예요?","JPN":"今は次元艦船も使って、光線も撃つ世の中なのに……そんなに脅威的なんですか？","ENG":"We're living in a world with dimensional ships and lasers... Are they that scary?","TWN":"現在都有次元艦船和雷射武器咧……他們真的那麼厲害嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"얕보면 안 돼. 구식 장비도 경기 중에 맞으면 사망 처리인 건 마찬가지야.","JPN":"侮っちゃいけないわ。旧式の装備でも試合中に当たれば死亡処理になるのは同じだからね。","ENG":"You mustn't underestimate them. Even old equipment can get you disqualified if you get hit.","TWN":"不能小看他們。就算是老舊裝備，在比賽中被打中的話，也是會死的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼 코치, 지금부터 전술 수립에 들어갈 건데…","JPN":"それではコーチ、今から戦術を立てますけど……","ENG":"Moving on, Coach, we're going to start laying out our strategy...","TWN":"所以教練，現在要開始來制定戰術……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"팀에 따로 주문하실 것 있을까요?","JPN":"チームに対する要望がありますか？","ENG":"Is there anything you would like to address to the team?","TWN":"你對隊員們還有別的要求嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"좋은 모습 보여 주게나.","JPN":"いい姿を見せてくれ。","ENG":"Show us your best.","TWN":"都好好表現。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그거라면……","JPN":"それなら……","ENG":"That...","TWN":"那樣的話……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쉬운 주문이구만. 설렁설렁 다녀와도 뭐라 하지 마셔.","JPN":"お安い御用だ。適当にやっても怒るなよ？","ENG":"Is an easy request. Don't be disappointed if we win without even breaking a sweat.","TWN":"那樣簡單。即使雙手空空地回來，也不要失望喔？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};